import{_ as t,H as a,f as o,i as c}from"./chunks/framework.nN4pLK1d.js";const h=JSON.parse('{"title":"Custom HTML","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/advanced/custom-html.md","filePath":"packages/rcml/email/concepts/advanced/custom-html.md"}'),r={name:"packages/rcml/email/concepts/advanced/custom-html.md"};function s(n,e,l,i,d,u){return a(),o("div",null,[...e[0]||(e[0]=[c('<h1>Custom HTML</h1><p><code>&lt;rc-raw&gt;</code> injects an HTML string verbatim into the compiled email output, bypassing all RCML structural checks. It is an escape hatch for cases that RCML&#39;s layout model cannot express.</p><p>RCML compiles to table-based HTML because that is the only layout model that renders consistently across all major email clients. This means the structural elements (<code>rc-section</code>, <code>rc-column</code>, etc.) map to <code>&lt;table&gt;</code>, <code>&lt;tr&gt;</code>, and <code>&lt;td&gt;</code> — a constrained subset of HTML. Anything that requires markup outside that model cannot be expressed through RCML elements, which is where <code>rc-raw</code> comes in.</p><h2 id="when-to-use-rc-raw" tabindex="-1">When to use <code>rc-raw</code> <a class="header-anchor" href="#when-to-use-rc-raw" aria-label="Permalink to &quot;When to use `rc-raw`&quot;">​</a></h2><ul><li><strong>Microsoft Office conditional comments</strong> — <code>&lt;!--[if mso]&gt;…&lt;![endif]--&gt;</code> for Outlook rendering fallbacks.</li><li><strong>Vendor-specific tracking pixels</strong> — when a pixel <code>&lt;img&gt;</code> tag must be placed exactly and <code>rc-image</code> adds unwanted wrapper markup.</li><li><strong>Structural HTML not expressible in RCML</strong> — rare edge cases requiring specific table or cell markup outside what the layout containers provide.</li></ul><h2 id="caution" tabindex="-1">Caution <a class="header-anchor" href="#caution" aria-label="Permalink to &quot;Caution&quot;">​</a></h2><p>Content in <code>rc-raw</code> is inserted as-is into the compiled output, bypassing all validation. Malformed HTML or unclosed tags don&#39;t just break the raw block — they can corrupt everything that follows it in the compiled email. The template may look correct in preview tools but render broken in a recipient&#39;s inbox. Because the error is silent, it can go undetected until a real send. Use standard RCML elements whenever they can express what you need, and keep <code>rc-raw</code> content minimal and well-tested.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-raw.html"><code>&lt;rc-raw&gt;</code> reference</a> — attributes and usage examples</li></ul>',9)])])}const p=t(r,[["render",s]]);export{h as __pageData,p as default};
